# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, exceptions as es_exceptions
import os

app = Flask(__name__)

ES_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ES_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")

es = Elasticsearch(
    ES_URL,
    request_timeout=float(os.getenv("ELASTICSEARCH_TIMEOUT", "2")),
    max_retries=int(os.getenv("ELASTICSEARCH_MAX_RETRIES", "2")),
    retry_on_timeout=True,
    http_compress=True,
)

def build_search_query(keyword):
    return {
        "size": 20,
        "track_total_hits": False,
        "_source": ["id", "name", "price", "image_url", "category", "rating", "stock"],
        "query": {
            "multi_match": {
                "query": keyword,
                "fields": ["name^4", "description^2", "category^2", "tags"],
                "type": "best_fields",
                "operator": "and",
                "fuzziness": "AUTO"
            }
        },
        "sort": [
            {"_score": "desc"},
            {"popularity": "desc"},
            {"_id": "asc"}
        ]
    }

@app.route("/api/search", methods=["GET"])
def search_products():
    keyword = request.args.get("q", "").strip()

    if not keyword:
        return jsonify({
            "error": "Missing required query parameter: q"
        }), 400

    try:
        response = es.search(index=ES_INDEX, body=build_search_query(keyword))
        hits = response.get("hits", {}).get("hits", [])

        products = []
        for hit in hits:
            source = hit.get("_source", {})
            source["score"] = hit.get("_score", 0)
            products.append(source)

        return jsonify({
            "query": keyword,
            "count": len(products),
            "products": products
        }), 200

    except es_exceptions.ConnectionError:
        return jsonify({
            "error": "Search service unavailable"
        }), 503
    except es_exceptions.TimeoutError:
        return jsonify({
            "error": "Search request timed out"
        }), 504
    except es_exceptions.TransportError:
        return jsonify({
            "error": "Search failed"
        }), 500

@app.route("/health", methods=["GET"])
def health():
    try:
        es.info()
        return jsonify({"status": "ok"}), 200
    except Exception:
        return jsonify({"status": "degraded"}), 503

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))